// ─── Reusable components ───

function Arrow({ horizontal } = {}) {
  return horizontal
    ? <span style={{ fontSize: "clamp(12px,1.5vw,20px)", color: T.mt }}>→</span>
    : <div style={{ fontSize: "clamp(12px,1.5vw,20px)", color: T.mt, textAlign: "center" }}>▼</div>;
}

function ArchBox({ color, label, sub, mono, children, style = {} }) {
  return (
    <div style={{ background: color, borderRadius: 5, padding: "1.2% 2.5%", textAlign: "center", fontFamily: mono ? "'Consolas','Courier New',monospace" : "Calibri,sans-serif", ...style }}>
      <div style={{ fontSize: "clamp(8px,1vw,13px)", color: "#fff", fontWeight: "bold" }}>{label}</div>
      {sub && <div style={{ fontSize: "clamp(6px,0.7vw,10px)", color: "rgba(255,255,255,0.75)", marginTop: 2 }}>{sub}</div>}
      {children}
    </div>
  );
}

function ScreenshotCard({ src, label, style = {}, imgStyle = {} }) {
  return (
    <div style={{ borderRadius: 6, overflow: "hidden", position: "relative", background: "#0E8585", display: "flex", flexDirection: "column", ...style }}>
      <img src={src} alt={label} style={{ width: "100%", flex: 1, objectFit: "cover", display: "block", minHeight: 0, ...imgStyle }} />
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, background: "linear-gradient(transparent, rgba(0,0,0,0.7))", padding: "6% 5% 3%", fontFamily: "Calibri,sans-serif", fontSize: "clamp(7px,0.8vw,11px)", color: "#fff", fontWeight: "bold" }}>{label}</div>
    </div>
  );
}

function TreeItem({ name, desc, indent = 0, folder = true, highlight = false, lang }) {
  const colors = { go: "#00ADD8", swift: "#F05138", js: "#F7DF1E", html: "#E34F26", liquid: "#7AB55C", sql: "#336791", yaml: "#CB171E" };
  return (
    <div style={{ display: "flex", alignItems: "center", gap: "0.8%", paddingLeft: `${indent * 2.5}%`, marginBottom: "0.6%" }}>
      <span style={{ fontFamily: "'Consolas','Courier New',monospace", fontSize: "clamp(8px,0.95vw,12px)", color: highlight ? T.sf : (folder ? T.tl : T.mu), fontWeight: folder ? "bold" : "normal" }}>
        {folder ? "📁" : "📄"} {name}
      </span>
      {lang && <span style={{ fontSize: "clamp(6px,0.6vw,8px)", background: colors[lang] || "#888", color: lang === "js" ? "#000" : "#fff", borderRadius: 3, padding: "0 4px", fontFamily: "Calibri,sans-serif", fontWeight: "bold" }}>{lang.toUpperCase()}</span>}
      {desc && <span style={{ fontFamily: "Calibri,sans-serif", fontSize: "clamp(7px,0.75vw,10px)", color: T.mu, marginLeft: "1%" }}>{desc}</span>}
    </div>
  );
}

